     1→/**
     2→ * AI Provider Fallback Service — Comprehensive Multi-Provider System
     3→ *
     4→ * Provides automatic failover between AI providers per modality.
     5→ * When a provider fails (401, 402, 429, timeout), automatically
     6→ * switches to the next provider in the chain. No manual intervention.
     7→ *
     8→ * Modalities: LLM, TTS, ASR, Vision, Embedding, Reranking, Safety
     9→ * Providers: Polsia/Anthropic, Polsia/OpenAI, NVIDIA NIM (20+ models)
    10→ *
    11→ * Per-module routing: Different HireLoop modules can request specialized
    12→ * chains optimized for their use case (e.g., reasoning models for assessments,
    13→ * cheap models for bulk onboarding, multimodal for resume parsing).
    14→ */
    15→
    16→const OpenAI = require('openai');
    17→const Anthropic = require('@anthropic-ai/sdk');
    18→const fetch = require('node-fetch');
    19→const FormData = require('form-data');
    20→
    21→// Circuit breaker: skip providers that failed recently
    22→const CIRCUIT_BREAK_MS = 5 * 60 * 1000; // 5 minutes
    23→
    24→// HTTP status codes that indicate provider-level issues (retryable)
    25→const RETRYABLE_STATUS = new Set([401, 402, 429, 500, 502, 503, 504]);
    26→
    27→// ─── NIM Model Registry ──────────────────────────────────────────
    28→// Complete catalog of NIM models organized by capability tier
    29→const NIM_MODELS = {
    30→  // LLM Models — ordered by quality/cost ratio
    31→  llm_super: process.env.NIM_LLM_MODEL || 'nvidia/llama-3.3-nemotron-super-49b-v1',
    32→  llm_deepseek_v3: process.env.NIM_LLM_DEEPSEEK_V3 || 'deepseek-ai/deepseek-v3p2',
    33→  llm_kimi: process.env.NIM_LLM_KIMI || 'moonshot-ai/kimi-k2.5',
    34→  llm_step_flash: process.env.NIM_LLM_STEP_FLASH || 'stepfun-ai/step-3.5-flash',
    35→  llm_gpt_oss: process.env.NIM_LLM_GPT_OSS || 'openai/gpt-oss-120b',
    36→  llm_nano: process.env.NIM_LLM_NANO || 'nvidia/nemotron-nano-8b-v2',
    37→  llm_deepseek_v3_1: process.env.NIM_LLM_DEEPSEEK_V3_1 || 'deepseek-ai/deepseek-v3p1',
    38→  llm_mistral_small: process.env.NIM_LLM_MISTRAL_SMALL || 'mistralai/mistral-small-24b-instruct-2501',
    39→  llm_qwen_72b: process.env.NIM_LLM_QWEN || 'qwen/qwen2.5-72b-instruct',
    40→
    41→  // Reasoning Models — for assessments, complex evaluation
    42→  reasoning_deepseek_r1: process.env.NIM_REASONING_R1 || 'deepseek-ai/deepseek-r1',
    43→  reasoning_qwq: process.env.NIM_REASONING_QWQ || 'qwen/qwq-32b',
    44→
    45→  // Vision Models — for body language, resume OCR, video analysis
    46→  vision_cosmos: process.env.NIM_VISION_MODEL || 'nvidia/cosmos-reason2-8b',
    47→  vision_nemotron_vl: process.env.NIM_VISION_FALLBACK_MODEL || 'nvidia/nemotron-nano-12b-v2-vl',
    48→  vision_kimi: process.env.NIM_VISION_KIMI || 'moonshot-ai/kimi-k2.5',
    49→  vision_gemma: process.env.NIM_VISION_GEMMA || 'google/gemma-3-27b-it',
    50→
    51→  // ASR Models — for speech recognition
    52→  asr_parakeet_v2: process.env.NIM_ASR_MODEL || 'nvidia/parakeet-tdt-0.6b-v2',
    53→  asr_parakeet_v3: process.env.NIM_ASR_V3 || 'nvidia/parakeet-tdt-0.6b-v3',
    54→
    55→  // Embedding Models — for job matching, profile similarity
    56→  embed_qa: process.env.NIM_EMBED_MODEL || 'nvidia/llama-3.2-nv-embedqa-1b-v2',
    57→  embed_vl: process.env.NIM_EMBED_VL || 'nvidia/llama-nemotron-embed-vl-1b-v2',
    58→
    59→  // Reranking Models — for search quality improvement
    60→  rerank_qa: process.env.NIM_RERANK_MODEL || 'nvidia/llama-3.2-nv-rerankqa-1b-v2',
    61→  rerank_vl: process.env.NIM_RERANK_VL || 'nvidia/llama-nemotron-rerank-vl-1b-v2',
    62→
    63→  // Safety Models — for content moderation
    64→  safety_guard: process.env.NIM_SAFETY_MODEL || 'nvidia/llama-3.1-nemotron-safety-guard-8b-v3',
    65→  safety_reasoning: process.env.NIM_SAFETY_REASONING || 'nvidia/nemotron-content-safety-reasoning-4b',
    66→
    67→  // Document/OCR Models — for resume parsing
    68→  document_parse: process.env.NIM_DOCUMENT_MODEL || 'nvidia/nemotron-parse',
    69→};
    70→
    71→// ─── Module-Specific Chain Preferences ───────────────────────────
    72→// Maps HireLoop modules to their optimal provider chain preferences
    73→const MODULE_CHAINS = {
    74→  // Mock Interview — needs quality LLM + TTS + ASR + Vision
    75→  'mock-interview': {
    76→    llm: 'quality',       // Best quality for evaluation
    77→    tts: 'default',
    78→    asr: 'default',
    79→    vision: 'default',
    80→  },
    81→  // AI Coaching — needs quality LLM
    82→  'coaching': {
    83→    llm: 'quality',
    84→  },
    85→  // Resume Parsing — needs vision/OCR + LLM extraction
    86→  'resume-parsing': {
    87→    llm: 'default',
    88→    vision: 'document',   // OCR-optimized chain
    89→  },
    90→  // Job Matching — needs embeddings + reranking
    91→  'job-matching': {
    92→    embedding: 'default',
    93→    reranking: 'default',
    94→    llm: 'efficient',     // Cheap LLM for explanation generation
    95→  },
    96→  // Onboarding — needs efficient LLM (simple Q&A)
    97→  'onboarding': {
    98→    llm: 'efficient',     // Cheap models for simple tasks
    99→  },
   100→  // Assessments — needs reasoning models for quality questions
   101→  'assessments': {
   102→    llm: 'reasoning',     // Reasoning models for complex evaluation
   103→  },
   104→  // Offer Management — needs efficient LLM for template generation
   105→  'offer-management': {
   106→    llm: 'efficient',
   107→  },
   108→  // Payroll — needs efficient LLM for calculations/Q&A
   109→  'payroll': {
   110→    llm: 'efficient',
   111→  },
   112→  // Interview Scheduling — needs efficient LLM
   113→  'scheduling': {
   114→    llm: 'efficient',
   115→  },
   116→  // Profile Management — needs embeddings
   117→  'profile': {
   118→    embedding: 'default',
   119→    llm: 'efficient',
   120→  },
   121→  // Platform Safety — needs safety models
   122→  'safety': {
   123→    safety: 'default',
   124→    llm: 'default',
   125→  },
   126→};
   127→
   128→
   129→class AIProviderService {
   130→  constructor() {
   131→    this.failures = {};          // { 'provider:modality': { count, lastFailure, error, status } }
   132→    this.activeProviders = {};   // { modality: providerKey }
   133→    this.logs = [];              // Recent failover events (last 100)
   134→    this.stats = {               // Cumulative stats
   135→      totalCalls: 0,
   136→      totalFailovers: 0,
   137→      providerCalls: {},         // { providerKey: count }
   138→    };
   139→
   140→    // Initialize clients
   141→    this.clients = {};
   142→    this.nimAvailable = false;
   143→    this._initClients();
   144→
   145→    console.log('[ai-provider] Initialized. NIM available:', this.nimAvailable);
   146→    console.log('[ai-provider] Providers:', Object.keys(this.clients).join(', '));
   147→    console.log('[ai-provider] Modalities: llm, vision, tts, asr, embedding, reranking, safety');
   148→  }
   149→
   150→  _initClients() {
   151→    // Anthropic client (Polsia proxy) — primary for LLM text
   152→    if (process.env.POLSIA_API_URL && process.env.POLSIA_API_KEY) {
   153→      this.clients.anthropic = new Anthropic({
   154→        baseURL: process.env.POLSIA_API_URL,
   155→        apiKey: process.env.POLSIA_API_KEY,
   156→      });
   157→    }
   158→
   159→    // OpenAI client (Polsia proxy) — primary for vision, TTS, ASR
   160→    if (process.env.OPENAI_BASE_URL && process.env.OPENAI_API_KEY) {
   161→      this.clients.openai = new OpenAI({
   162→        baseURL: process.env.OPENAI_BASE_URL,
   163→        apiKey: process.env.OPENAI_API_KEY,
   164→      });
   165→      this.openaiBaseUrl = process.env.OPENAI_BASE_URL;
   166→      this.openaiApiKey = process.env.OPENAI_API_KEY;
   167→    }
   168→
   169→    // NVIDIA NIM client — fallback for all modalities
   170→    const nimKey = process.env.NVIDIA_NIM_API_KEY;
   171→    const nimBase = process.env.NIM_BASE_URL || 'https://integrate.api.nvidia.com/v1';
   172→    if (nimKey) {
   173→      this.clients.nim = new OpenAI({
   174→        baseURL: nimBase,
   175→        apiKey: nimKey,
   176→      });
   177→      this.nimBaseUrl = nimBase;
   178→      this.nimApiKey = nimKey;
   179→      this.nimAvailable = true;
   180→    }
   181→  }
   182→
   183→  // ─── Fallback Chain Definitions ───────────────────────────────
   184→
   185→  /**
   186→   * Get the fallback chain for a modality, optionally specialized per module.
   187→   * @param {string} modality - 'llm', 'vision', 'tts', 'asr', 'embedding', 'reranking', 'safety'
   188→   * @param {string} variant - Chain variant: 'default', 'quality', 'efficient', 'reasoning', 'document'
   189→   * @returns {string[]} Array of provider keys to try in order
   190→   */
   191→  getChain(modality, variant = 'default') {
   192→    const chains = {
   193→      // ─── LLM Chains (5-7 providers deep) ─────────────────
   194→      llm: {
   195→        // Default: balanced quality and cost
   196→        default: [
   197→          'anthropic',           // Polsia/Claude — current primary
   198→          'openai',              // Polsia/OpenAI GPT-4o-mini
   199→          'nim_nemotron_super',  // NIM Nemotron Super 49B — best value
   200→          'nim_kimi',            // NIM Kimi K2.5 — 1T MoE multimodal
   201→          'nim_deepseek_v3',     // NIM DeepSeek V3.2 — GPT-5 level
   202→          'nim_step_flash',      // NIM Step 3.5 Flash — ultra efficient
   203→          'nim_gpt_oss',         // NIM GPT-OSS-120B — OpenAI open model
   204→        ],
   205→        // Quality: best models first for critical tasks (interviews, coaching)
   206→        quality: [
   207→          'anthropic',
   208→          'openai',
   209→          'nim_deepseek_v3',     // DeepSeek V3.2 — strongest open model
   210→          'nim_kimi',            // Kimi K2.5 — multimodal reasoning
   211→          'nim_nemotron_super',  // Nemotron Super 49B
   212→          'nim_step_flash',
   213→          'nim_gpt_oss',
   214→        ],
   215→        // Efficient: cheapest models first for bulk/simple tasks
   216→        efficient: [
   217→          'anthropic',
   218→          'openai',
   219→          'nim_nano',            // Nemotron Nano 9B — $0.04/$0.16
   220→          'nim_mistral_small',   // Mistral Small 24B — $0.20/$0.60
   221→          'nim_nemotron_super',  // Nemotron Super 49B — $0.10/$0.40
   222→          'nim_gpt_oss',
   223→        ],
   224→        // Reasoning: models with strong reasoning for assessments
   225→        reasoning: [
   226→          'anthropic',
   227→          'openai',
   228→          'nim_step_flash',      // Step 3.5 Flash — 97.3% AIME champion
   229→          'nim_deepseek_v3',     // DeepSeek V3.2 — strong reasoning
   230→          'nim_kimi',            // Kimi K2.5 — thinking mode
   231→          'nim_nemotron_super',
   232→        ],
   233→      },
   234→
   235→      // ─── Vision Chains (3-4 providers deep) ──────────────
   236→      vision: {
   237→        default: [
   238→          'openai_vision',       // Polsia/OpenAI GPT-4o
   239→          'nim_cosmos',          // NIM Cosmos Reason2 8B
   240→          'nim_nemotron_vl',     // NIM Nemotron Nano 12B VL
   241→          'nim_kimi_vision',     // NIM Kimi K2.5 (multimodal)
   242→        ],
   243→        // Document/OCR chain for resume parsing
   244→        document: [
   245→          'openai_vision',       // Polsia/OpenAI GPT-4o
   246→          'nim_nemotron_vl',     // NIM Nemotron Nano 12B VL — good at documents
   247→          'nim_kimi_vision',     // NIM Kimi K2.5 — PDF native
   248→          'nim_cosmos',          // NIM Cosmos Reason2 8B
   249→        ],
   250→      },
   251→
   252→      // ─── TTS Chains (2 providers + browser fallback) ─────
   253→      tts: {
   254→        default: [
   255→          'openai_tts',          // Polsia/OpenAI TTS-1 — primary
   256→          'nim_riva_tts',        // NIM Riva TTS — NVIDIA speech synthesis
   257→          // Browser Web Speech API handled at frontend level as final fallback
   258→        ],
   259→      },
   260→
   261→      // ─── ASR Chains (3 providers deep) ────────────────────
   262→      asr: {
   263→        default: [
   264→          'openai_whisper',      // Polsia/OpenAI Whisper — primary
   265→          'nim_parakeet_v2',     // NIM Parakeet TDT 0.6B v2 — English #1
   266→          'nim_parakeet_v3',     // NIM Parakeet TDT 0.6B v3 — 25 languages
   267→        ],
   268→      },
   269→
   270→      // ─── Embedding Chains (3 providers deep) ─────────────
   271→      embedding: {
   272→        default: [
   273→          'openai_embed',        // Polsia/OpenAI text-embedding-3-small
   274→          'nim_embed_qa',        // NIM NV-EmbedQA 1B v2 — 26 languages
   275→          'nim_embed_vl',        // NIM Nemotron-Embed-VL 1B — multimodal
   276→        ],
   277→      },
   278→
   279→      // ─── Reranking Chains (2 providers) ──────────────────
   280→      reranking: {
   281→        default: [
   282→          'nim_rerank_qa',       // NIM NV-RerankQA 1B v2 — text reranking
   283→          'nim_rerank_vl',       // NIM Nemotron-Rerank-VL 1B — multimodal
   284→        ],
   285→      },
   286→
   287→      // ─── Safety/Guardrails Chains (2 providers) ──────────
   288→      safety: {
   289→        default: [
   290→          'nim_safety_guard',    // NIM NemoGuard Safety 8B — 23 categories
   291→          'nim_safety_reasoning',// NIM Nemotron Content Safety 4B
   292→        ],
   293→      },
   294→    };
   295→
   296→    const modalityChains = chains[modality];
   297→    if (!modalityChains) return [];
   298→    return modalityChains[variant] || modalityChains.default || [];
   299→  }
   300→
   301→  /**
   302→   * Get the optimal chain for a specific HireLoop module + modality.
   303→   * Falls back to default chain if no module-specific config exists.
   304→   */
   305→  getModuleChain(module, modality) {
   306→    const moduleConfig = MODULE_CHAINS[module];
   307→    const variant = (moduleConfig && moduleConfig[modality]) || 'default';
   308→    return this.getChain(modality, variant);
   309→  }
   310→
   311→  // Check if a provider is available (has required client/keys)
   312→  isProviderAvailable(providerKey) {
   313→    switch (providerKey) {
   314→      case 'anthropic':
   315→        return !!this.clients.anthropic;
   316→      case 'openai':
   317→      case 'openai_vision':
   318→      case 'openai_tts':
   319→      case 'openai_whisper':
   320→      case 'openai_embed':
   321→        return !!this.clients.openai;
   322→      // All NIM providers require NIM API key
   323→      case 'nim_nemotron_super':
   324→      case 'nim_kimi':
   325→      case 'nim_deepseek_v3':
   326→      case 'nim_step_flash':
   327→      case 'nim_gpt_oss':
   328→      case 'nim_nano':
   329→      case 'nim_mistral_small':
   330→      case 'nim_cosmos':
   331→      case 'nim_nemotron_vl':
   332→      case 'nim_kimi_vision':
   333→      case 'nim_riva_tts':
   334→      case 'nim_parakeet_v2':
   335→      case 'nim_parakeet_v3':
   336→      case 'nim_embed_qa':
   337→      case 'nim_embed_vl':
   338→      case 'nim_rerank_qa':
   339→      case 'nim_rerank_vl':
   340→      case 'nim_safety_guard':
   341→      case 'nim_safety_reasoning':
   342→        return this.nimAvailable;
   343→      default:
   344→        return false;
   345→    }
   346→  }
   347→
   348→  // ─── Circuit Breaker ──────────────────────────────────────────
   349→
   350→  isCircuitOpen(providerKey, modality) {
   351→    const key = `${providerKey}:${modality}`;
   352→    const failure = this.failures[key];
   353→    if (!failure) return false;
   354→
   355→    const elapsed = Date.now() - failure.lastFailure;
   356→    if (elapsed > CIRCUIT_BREAK_MS) {
   357→      // Circuit closed — enough time passed, allow retry
   358→      delete this.failures[key];
   359→      return false;
   360→    }
   361→    return true;
   362→  }
   363→
   364→  recordFailure(providerKey, modality, error) {
   365→    const key = `${providerKey}:${modality}`;
   366→    const existing = this.failures[key] || { count: 0 };
   367→    const status = error.status || error.statusCode || null;
   368→
   369→    this.failures[key] = {
   370→      count: existing.count + 1,
   371→      lastFailure: Date.now(),
   372→      error: error.message || String(error),
   373→      status,
   374→    };
   375→
   376→    this.stats.totalFailovers++;
   377→
   378→    const logEntry = {
   379→      timestamp: new Date().toISOString(),
   380→      event: 'provider_failure',
   381→      provider: providerKey,
   382→      modality,
   383→      error: error.message || String(error),
   384→      status,
   385→    };
   386→    this.logs.push(logEntry);
   387→    if (this.logs.length > 100) this.logs.shift();
   388→
   389→    console.log(`[ai-provider] ❌ ${providerKey} failed for ${modality}: [${status || 'ERR'}] ${error.message || error}`);
   390→  }
   391→
   392→  recordSuccess(providerKey, modality) {
   393→    this.activeProviders[modality] = providerKey;
   394→    const key = `${providerKey}:${modality}`;
   395→    delete this.failures[key];
   396→
   397→    this.stats.totalCalls++;
   398→    this.stats.providerCalls[providerKey] = (this.stats.providerCalls[providerKey] || 0) + 1;
   399→  }
   400→
   401→  isRetryable(err) {
   402→    // Network/timeout errors
   403→    if (err.code === 'ETIMEDOUT' || err.code === 'ECONNREFUSED' || err.code === 'ECONNRESET' || err.code === 'ENOTFOUND') return true;
   404→    if (err.message && (err.message.includes('timeout') || err.message.includes('ETIMEDOUT'))) return true;
   405→
   406→    // HTTP status codes
   407→    const status = err.status || err.statusCode || (err.response && err.response.status);
   408→    if (status && RETRYABLE_STATUS.has(status)) return true;
   409→
   410→    // OpenAI SDK-specific error types
   411→    if (err.type === 'insufficient_quota' || err.code === 'insufficient_quota') return true;
   412→    if (err.type === 'rate_limit_exceeded' || err.code === 'rate_limit_exceeded') return true;
   413→
   414→    // Anthropic-specific
   415→    if (err.error && err.error.type === 'overloaded_error') return true;
   416→
   417→    return false;
   418→  }
   419→
   420→  // Get available providers for a modality (skipping unavailable + circuit-broken)
   421→  getAvailableChain(modality, variant = 'default') {
   422→    return this.getChain(modality, variant).filter(key =>
   423→      this.isProviderAvailable(key) && !this.isCircuitOpen(key, modality)
   424→    );
   425→  }
   426→
   427→  // ─── Core Execution with Fallback ────────────────────────────
   428→
   429→  /**
   430→   * Execute an AI call with automatic fallback.
   431→   * @param {string} modality - 'llm', 'vision', 'tts', 'asr', 'embedding', 'reranking', 'safety'
   432→   * @param {Function} executeFn - async (providerKey) => result
   433→   * @param {string} variant - Chain variant (default, quality, efficient, reasoning)
   434→   * @returns {*} Result from the first successful provider
   435→   */
   436→  async execute(modality, executeFn, variant = 'default') {
   437→    const chain = this.getAvailableChain(modality, variant);
   438→
   439→    if (chain.length === 0) {
   440→      const allChain = this.getChain(modality, variant);
   441→      const reasons = allChain.map(k => {
   442→        if (!this.isProviderAvailable(k)) return `${k}: not configured`;
   443→        if (this.isCircuitOpen(k, modality)) return `${k}: circuit open`;
   444→        return `${k}: unknown`;
   445→      });
   446→      throw new Error(`No available providers for ${modality}. ${reasons.join(', ')}`);
   447→    }
   448→
   449→    let lastError;
   450→    for (const providerKey of chain) {
   451→      try {
   452→        const result = await executeFn(providerKey);
   453→        this.recordSuccess(providerKey, modality);
   454→        return result;
   455→      } catch (err) {
   456→        lastError = err;
   457→        if (this.isRetryable(err)) {
   458→          this.recordFailure(providerKey, modality, err);
   459→          continue; // try next provider
   460→        }
   461→        // Non-retryable error (e.g., bad request, invalid input) — don't try others
   462→        throw err;
   463→      }
   464→    }
   465→
   466→    // All providers exhausted
   467→    console.error(`[ai-provider] All ${modality} providers exhausted.`);
   468→    throw lastError || new Error(`All ${modality} providers failed`);
   469→  }
   470→
   471→  // ─── LLM Chat Completion ─────────────────────────────────────
   472→
   473→  /**
   474→   * Chat completion with automatic provider fallback.
   475→   * @param {Array} messages - Array of { role, content } messages
   476→   * @param {Object} options - { system, maxTokens, max_tokens, temperature, subscriptionId, response_format, module }
   477→   * @returns {string} The AI response text
   478→   */
   479→  async chatCompletion(messages, options = {}) {
   480→    // Determine chain variant based on module
