   716→  /**
   717→   * NIM Riva TTS — NVIDIA's speech synthesis via REST API.
   718→   * Uses the /v1/audio/synthesize endpoint format.
   719→   * Returns WAV audio buffer.
   720→   */
   721→  async _nimRivaTTS(text, options) {
   722→    const truncatedText = text.length > 4000 ? text.substring(0, 4000) : text;
   723→    const language = options.language || 'en-US';
   724→
   725→    // Riva TTS uses a different endpoint format than OpenAI
   726→    // POST /v1/audio/synthesize with form-data
   727→    const formData = new FormData();
   728→    formData.append('text', truncatedText);
   729→    formData.append('language', language);
   730→    if (options.nimVoice) {
   731→      formData.append('voice', options.nimVoice);
   732→    }
   733→
   734→    const nimTtsBase = process.env.NIM_TTS_BASE_URL || this.nimBaseUrl;
   735→    const res = await fetch(`${nimTtsBase}/audio/synthesize`, {
   736→      method: 'POST',
   737→      headers: {
   738→        'Authorization': `Bearer ${this.nimApiKey}`,
   739→        'Accept': 'audio/wav',
   740→        ...formData.getHeaders(),
   741→      },
   742→      body: formData,
   743→    });
   744→
   745→    if (!res.ok) {
   746→      const errText = await res.text();
   747→      const err = new Error(`NIM Riva TTS error: ${res.status} ${errText.substring(0, 200)}`);
   748→      err.status = res.status;
   749→      throw err;
   750→    }
   751→
   752→    const arrayBuffer = await res.arrayBuffer();
   753→    const buffer = Buffer.from(arrayBuffer);
   754→
   755→    if (buffer.length < 100) {
   756→      throw new Error('NIM Riva TTS returned empty/invalid audio');
   757→    }
   758→
   759→    return buffer;
   760→  }
