   905→  // ─── Reranking ───────────────────────────────────────────────
   906→
   907→  /**
   908→   * Rerank search results for quality improvement.
   909→   * Uses NIM NV-RerankQA model to reorder candidate/job matches.
   910→   * @param {string} query - The search query
   911→   * @param {string[]} documents - Array of document texts to rerank
   912→   * @param {Object} options - { topN }
   913→   * @returns {Array} Reranked results with scores
   914→   */
   915→  async rerank(query, documents, options = {}) {
   916→    if (!this.nimAvailable) {
   917→      // No NIM = return original order with default scores
   918→      console.log('[ai-provider] Reranking skipped (NIM not available), returning original order');
   919→      return documents.map((doc, i) => ({ index: i, score: 1 - (i * 0.01), text: doc }));
   920→    }
   921→
   922→    try {
   923→      return await this.execute('reranking', async (providerKey) => {
   924→        let model;
   925→        switch (providerKey) {
   926→          case 'nim_rerank_qa':
   927→            model = NIM_MODELS.rerank_qa;
   928→            break;
   929→          case 'nim_rerank_vl':
   930→            model = NIM_MODELS.rerank_vl;
   931→            break;
   932→          default:
   933→            throw new Error(`Unknown reranking provider: ${providerKey}`);
   934→        }
   935→
   936→        const topN = options.topN || documents.length;
   937→
   938→        // NIM reranking endpoint
   939→        const res = await fetch(`${this.nimBaseUrl}/ranking`, {
   940→          method: 'POST',
   941→          headers: {
   942→            'Authorization': `Bearer ${this.nimApiKey}`,
   943→            'Content-Type': 'application/json',
   944→          },
   945→          body: JSON.stringify({
   946→            model,
   947→            query: { text: query },
   948→            passages: documents.map(doc => ({ text: doc })),
   949→            top_n: topN,
   950→          }),
   951→        });
   952→
   953→        if (!res.ok) {
   954→          const errText = await res.text();
   955→          const err = new Error(`NIM Reranking error: ${res.status} ${errText.substring(0, 200)}`);
   956→          err.status = res.status;
   957→          throw err;
   958→        }
   959→
   960→        const result = await res.json();
   961→        return (result.rankings || []).map(r => ({
   962→          index: r.index,
   963→          score: r.logit || r.score || 0,
   964→          text: documents[r.index],
   965→        }));
   966→      });
   967→    } catch (err) {
   968→      console.error('[ai-provider] Reranking failed, returning original order:', err.message);
   969→      return documents.map((doc, i) => ({ index: i, score: 1 - (i * 0.01), text: doc }));
   970→    }
   971→  }
