   973→  // ─── Safety / Content Moderation ─────────────────────────────
   974→
   975→  /**
   976→   * Check content for safety violations using NIM NemoGuard.
   977→   * @param {string} content - Text to check
   978→   * @param {Object} options - { categories }
   979→   * @returns {Object} { safe: boolean, categories: {...}, reason: string }
   980→   */
   981→  async moderateContent(content, options = {}) {
   982→    if (!this.nimAvailable) {
   983→      // No NIM = allow all (no moderation available)
   984→      return { safe: true, categories: {}, reason: 'Moderation not available (NIM not configured)' };
   985→    }
   986→
   987→    try {
   988→      return await this.execute('safety', async (providerKey) => {
   989→        let model;
   990→        switch (providerKey) {
   991→          case 'nim_safety_guard':
   992→            model = NIM_MODELS.safety_guard;
   993→            break;
   994→          case 'nim_safety_reasoning':
   995→            model = NIM_MODELS.safety_reasoning;
   996→            break;
   997→          default:
   998→            throw new Error(`Unknown safety provider: ${providerKey}`);
   999→        }
  1000→
  1001→        // NemoGuard uses chat completions format with safety-specific system prompt
  1002→        const response = await this.clients.nim.chat.completions.create({
  1003→          model,
  1004→          messages: [
  1005→            {
  1006→              role: 'system',
  1007→              content: 'You are a content safety classifier. Analyze the following text for safety violations including: harassment, hate speech, violence, sexual content, self-harm, dangerous content, and professional misconduct. Return a JSON object: {"safe": true/false, "categories": {"harassment": false, "hate_speech": false, "violence": false, "sexual_content": false, "self_harm": false, "dangerous": false, "unprofessional": false}, "reason": "explanation if unsafe"}'
  1008→            },
  1009→            { role: 'user', content: content.substring(0, 4000) }
  1010→          ],
  1011→          max_tokens: 512,
  1012→          temperature: 0.1,
  1013→        });
  1014→
  1015→        const text = response.choices[0].message.content;
  1016→        try {
  1017→          const jsonMatch = text.match(/\{[\s\S]*\}/);
  1018→          if (jsonMatch) return JSON.parse(jsonMatch[0]);
  1019→        } catch (e) { /* fall through */ }
  1020→
  1021→        // Default safe if parsing fails
  1022→        return { safe: true, categories: {}, reason: 'Safety check completed (parse fallback)' };
  1023→      });
  1024→    } catch (err) {
  1025→      console.error('[ai-provider] Safety moderation failed:', err.message);
  1026→      return { safe: true, categories: {}, reason: 'Safety check failed (allowing by default)' };
  1027→    }
  1028→  }
