  1030→  // ─── Health Status ────────────────────────────────────────────
  1031→
  1032→  getHealth() {
  1033→    const allModalities = ['llm', 'vision', 'tts', 'asr', 'embedding', 'reranking', 'safety'];
  1034→    const modalities = {};
  1035→
  1036→    for (const modality of allModalities) {
  1037→      const chain = this.getChain(modality);
  1038→      modalities[modality] = {
  1039→        active: this.activeProviders[modality] || 'none',
  1040→        chain_depth: chain.length,
  1041→        providers: chain.map(key => ({
  1042→          key,
