  _initClients() {
    // Anthropic client (Polsia proxy) — primary for LLM text
    if (process.env.POLSIA_API_URL && process.env.POLSIA_API_KEY) {
      this.clients.anthropic = new Anthropic({
        baseURL: process.env.POLSIA_API_URL,
