      embedding: {
        default: [
          'openai_embed',        // Polsia/OpenAI text-embedding-3-small
          'nim_embed_qa',        // NIM NV-EmbedQA 1B v2 — 26 languages
          'nim_embed_vl',        // NIM Nemotron-Embed-VL 1B — multimodal
        ],
      },

      // ─── Reranking Chains (2 providers) ──────────────────
      reranking: {
        default: [
